#include <algorithm>
#include <cmath>

#include "primer/hyperloglog_presto.h"

namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : cardinality_(0), n_leading_bits_(n_leading_bits) {
  // Initialize the number of buckets and dense bucket array
  if (n_leading_bits <= 0) {
    num_buckets_ = 0;
    dense_bucket_.clear();
  } else {
    num_buckets_ = 1 << n_leading_bits;  // 2^n_leading_bits
    dense_bucket_.assign(num_buckets_, std::bitset<DENSE_BUCKET_SIZE>(0));
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ <= 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate hash of the element
  hash_t hash = CalculateHash(val);

  // Split the hash into two parts
  // First n_leading_bits determine the bucket index
  uint64_t bucket_idx = hash & ((1ULL << n_leading_bits_) - 1);

  // The remaining bits after removing the first n_leading_bits
  uint64_t remaining_bits = hash >> n_leading_bits_;

  // Find the position of the first 1-bit from the right (rho - leading zero count + 1)
  // If remaining_bits is 0, position is maximum
  uint64_t leading_one_pos = 0;

  if (remaining_bits == 0) {
    // All remaining bits are 0, set position to maximum
    // This represents infinite leading zeros
    leading_one_pos = 64 - n_leading_bits_;
  } else {
    // Find the position of the first 1-bit from the right
    for (uint64_t i = 0; i < 64 - n_leading_bits_; ++i) {
      if ((remaining_bits >> i) & 1ULL) {
        // Add 1 to position only if n_leading_bits > 0
        leading_one_pos = (n_leading_bits_ > 0) ? (i + 1) : i;
        break;
      }
    }
  }

  // Encode the position using dense bucket (4 bits) and overflow bucket (3 bits)
  // Dense bucket stores the lower 4 bits
  uint64_t dense_val = leading_one_pos & 0xF;  // Lower 4 bits
  uint64_t overflow_val = (leading_one_pos >> 4) & 0x7;  // Next 3 bits

  // Update buckets with maximum value seen
  uint64_t current_dense = dense_bucket_[bucket_idx].to_ullong();
  uint64_t current_overflow = (overflow_bucket_.count(bucket_idx) > 0 ? overflow_bucket_[bucket_idx].to_ullong() : 0);
  uint64_t current_full_pos = (current_overflow << 4) | current_dense;
  uint64_t new_full_pos = (overflow_val << 4) | dense_val;

  if (new_full_pos > current_full_pos) {
    dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(dense_val);
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(overflow_val);
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::ComputeCardinality() -> void {
  if (n_leading_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate the harmonic mean of 2^(-M[i])
  double raw_estimate = 0.0;
  for (uint64_t i = 0; i < num_buckets_; ++i) {
    // Get the full position value from dense and overflow buckets
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = (overflow_bucket_.count(i) > 0 ? overflow_bucket_[i].to_ullong() : 0);
    uint64_t full_pos = (overflow_val << 4) | dense_val;

    raw_estimate += std::pow(2.0, -static_cast<double>(full_pos));
  }

  // Cardinality = α_m * m^2 / sum(2^(-M[i]))
  // where α_m = 0.79402 for our implementation
  double alpha_m = CONSTANT;
  double cardinality_estimate = alpha_m * num_buckets_ * num_buckets_ / raw_estimate;

  cardinality_ = static_cast<uint64_t>(cardinality_estimate);
}

template class HyperLogLogPresto<int64_t>;
template class HyperLogLogPresto<std::string>;
}  // namespace bustub

