#include "primer/hyperloglog.h"

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : cardinality_(0), n_bits_(n_bits) {
  // Initialize the number of buckets and registers
  if (n_bits < 0) {
    num_buckets_ = 0;
    registers_.clear();
  } else {
    num_buckets_ = 1 << n_bits;  // 2^n_bits
    registers_.assign(num_buckets_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  // Convert hash to bitset
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost (most significant) 1-bit
  // Return the count from the right (0-indexed position + 1)
  for (int64_t i = BITSET_CAPACITY - 1; i >= 0; --i) {
    if (bset[i]) {
      return (BITSET_CAPACITY - i);
    }
  }
  return 0;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ < 0 || num_buckets_ == 0) {
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate hash of the element
  hash_t hash = CalculateHash(val);

  // Split the hash into two parts
  // First n_bits determine the bucket index
  uint64_t bucket_idx = hash & ((1ULL << n_bits_) - 1);

  // The remaining bits after removing the first n_bits
  uint64_t remaining_bits = hash >> n_bits_;

  // Find the position of the first 1-bit from the right (rho - leading zero count + 1)
  // If remaining_bits is 0, position is max (all remaining bits are 0)
  uint64_t leading_one_pos = 0;
  if (remaining_bits == 0) {
    leading_one_pos = 64 - n_bits_;
  } else {
    // Find the position of the first 1-bit from the right
    for (uint64_t i = 0; i < 64 - n_bits_; ++i) {
      if ((remaining_bits >> i) & 1ULL) {
        leading_one_pos = i + 1;
        break;
      }
    }
  }

  // Update the register with the maximum leading one position
  registers_[bucket_idx] = std::max(registers_[bucket_idx], leading_one_pos);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (n_bits_ < 0 || num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> lock(mutex_);

  // Calculate the harmonic mean of 2^(-M[i])
  double raw_estimate = 0.0;
  for (uint64_t i = 0; i < num_buckets_; ++i) {
    raw_estimate += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  // Cardinality = α_m * m^2 / sum(2^(-M[i]))
  // where α_m = 0.79402 for our implementation
  double alpha_m = CONSTANT;
  double cardinality_estimate = alpha_m * num_buckets_ * num_buckets_ / raw_estimate;

  cardinality_ = static_cast<size_t>(cardinality_estimate);
}

template class HyperLogLog<int64_t>;
template class HyperLogLog<std::string>;

}  // namespace bustub

